+import { getCopy } from "../shared/i18n";
+import type {
+  AgentAction,
+  AgentControlMode,
+  AgentEvent,
+  BenchmarkToolRequest,
+  BenchmarkToolResult,
+  DomObservation,
+  ExtensionSettings,
