+  if (result.type === "report") {
+    return {
+      kind: "final",
+      title: result.title,
+      detail: "HTML report ready.",
+      html: result.html
+    };
+  }
+  if (result.type === "rewrite") {
+    return {
+      kind: "result",
+      title: result.title,
+      detail: `Changed ${result.rewrite.changed} text nodes.`,
+      meta: result.rewrite.sessionId
+    };
